    /**
     * Hash a password securely using PHP's password_hash with bcrypt
     */
    public function hash_password($password) {
        return password_hash($password, PASSWORD_BCRYPT, array('cost' => 12));
    }

    /**
     * Verify a password against its hash
     */
    public function verify_password($password, $hash) {
        return password_verify($password, $hash);
    }

    /**
     * Check if a password hash needs to be rehashed (e.g., if cost factor changed)
     */
    public function needs_rehash($hash) {
        return password_needs_rehash($hash, PASSWORD_BCRYPT, array('cost' => 12));
    }

    /**
     * Validate password strength
     */
    public function validate_password_strength($password) {
        $errors = array();
        $min_length = get_option('custom_auth_min_password_length', 8);
        $require_special = get_option('custom_auth_require_special_chars', true);

        if (strlen($password) < $min_length) {
            $errors[] = sprintf(__('Password must be at least %d characters long.', 'custom-user-auth'), $min_length);
        }

        if (!preg_match('/[A-Z]/', $password)) {
            $errors[] = __('Password must contain at least one uppercase letter.', 'custom-user-auth');
        }

        if (!preg_match('/[a-z]/', $password)) {
            $errors[] = __('Password must contain at least one lowercase letter.', 'custom-user-auth');
        }

        if (!preg_match('/[0-9]/', $password)) {
            $errors[] = __('Password must contain at least one number.', 'custom-user-auth');
        }

        if ($require_special && !preg_match('/[!@#$%^&*(),.?":{}|<>]/', $password)) {
            $errors[] = __('Password must contain at least one special character.', 'custom-user-auth');
        }

        return $errors;
    }

    /**
     * Check if account is locked due to too many failed attempts
     */
    public function is_account_locked($user) {
        $max_attempts = get_option('custom_auth_max_login_attempts', 5);
        $lockout_duration = get_option('custom_auth_lockout_duration', 15);

        if ($user->login_attempts >= $max_attempts && $user->last_login_attempt) {
            $lockout_time = strtotime($user->last_login_attempt) + ($lockout_duration * 60);
            if (time() < $lockout_time) {
                return true;
            }
        }

        return false;
    }

    /**
     * Handle user registration
     */
    public function handle_registration() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        global $wpdb;

        $username = sanitize_user(isset($_POST['username']) ? $_POST['username'] : '');
        $email = sanitize_email(isset($_POST['email']) ? $_POST['email'] : '');
        $password = isset($_POST['password']) ? $_POST['password'] : '';
        $confirm_password = isset($_POST['confirm_password']) ? $_POST['confirm_password'] : '';
        $first_name = sanitize_text_field(isset($_POST['first_name']) ? $_POST['first_name'] : '');
        $last_name = sanitize_text_field(isset($_POST['last_name']) ? $_POST['last_name'] : '');

        $errors = array();

        // Validate username
        if (empty($username)) {
            $errors[] = __('Username is required.', 'custom-user-auth');
        } elseif (strlen($username) < 3) {
            $errors[] = __('Username must be at least 3 characters long.', 'custom-user-auth');
        } elseif (!preg_match('/^[a-zA-Z0-9_]+$/', $username)) {
            $errors[] = __('Username can only contain letters, numbers, and underscores.', 'custom-user-auth');
        }

        // Validate email
        if (empty($email) || !is_email($email)) {
            $errors[] = __('A valid email address is required.', 'custom-user-auth');
        }

        // Validate password
        if (empty($password)) {
            $errors[] = __('Password is required.', 'custom-user-auth');
        } else {
            $password_errors = $this->validate_password_strength($password);
            $errors = array_merge($errors, $password_errors);
        }

        // Confirm password match
        if ($password !== $confirm_password) {
            $errors[] = __('Passwords do not match.', 'custom-user-auth');
        }

        // Check if username exists
        $existing_user = $wpdb->get_row(
            $wpdb->prepare("SELECT id FROM {$this->table_name} WHERE username = %s", $username)
        );
        if ($existing_user) {
            $errors[] = __('Username already exists.', 'custom-user-auth');
        }

        // Check if email exists
        $existing_email = $wpdb->get_row(
            $wpdb->prepare("SELECT id FROM {$this->table_name} WHERE email = %s", $email)
        );
        if ($existing_email) {
            $errors[] = __('Email address already registered.', 'custom-user-auth');
        }

        if (!empty($errors)) {
            wp_send_json_error(array('messages' => $errors));
            return;
        }

        // Hash the password
        $password_hash = $this->hash_password($password);

        // Insert user
        $result = $wpdb->insert(
            $this->table_name,
            array(
                'username' => $username,
                'email' => $email,
                'password_hash' => $password_hash,
                'first_name' => $first_name,
                'last_name' => $last_name,
                'status' => 'active',
                'created_at' => current_time('mysql'),
            ),
            array('%s', '%s', '%s', '%s', '%s', '%s', '%s')
        );

        if ($result === false) {
            wp_send_json_error(array('messages' => array(__('Registration failed. Please try again.', 'custom-user-auth'))));
            return;
        }

        do_action('custom_auth_user_registered', $wpdb->insert_id, $username, $email);

        wp_send_json_success(array(
            'message' => __('Registration successful! You can now log in.', 'custom-user-auth'),
        ));
    }

    /**
     * Handle user login
     */
    public function handle_login() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        global $wpdb;

        $username_or_email = sanitize_text_field(isset($_POST['username']) ? $_POST['username'] : '');
        $password = isset($_POST['password']) ? $_POST['password'] : '';
        $remember = isset($_POST['remember']) ? (bool) $_POST['remember'] : false;

        $errors = array();

        if (empty($username_or_email)) {
            $errors[] = __('Username or email is required.', 'custom-user-auth');
        }

        if (empty($password)) {
            $errors[] = __('Password is required.', 'custom-user-auth');
        }

        if (!empty($errors)) {
            wp_send_json_error(array('messages' => $errors));
            return;
        }

        // Find user by username or email
        $user = $wpdb->get_row(
            $wpdb->prepare(
                "SELECT * FROM {$this->table_name} WHERE username = %s OR email = %s",
                $username_or_email,
                $username_or_email
            )
        );

        if (!$user) {
            wp_send_json_error(array('messages' => array(__('Invalid username/email or password.', 'custom-user-auth'))));
            return;
        }

        // Check if account is active
        if ($user->status !== 'active') {
            wp_send_json_error(array('messages' => array(__('Your account has been deactivated. Please contact support.', 'custom-user-auth'))));
            return;
        }

        // Check if account is locked
        if ($this->is_account_locked($user)) {
            $lockout_duration = get_option('custom_auth_lockout_duration', 15);
            wp_send_json_error(array(
                'messages' => array(
                    sprintf(
                        __('Account temporarily locked due to too many failed attempts. Please try again in %d minutes.', 'custom-user-auth'),
                        $lockout_duration
                    )
                )
            ));
            return;
        }

        // Verify password
        if (!$this->verify_password($password, $user->password_hash)) {
            // Increment login attempts
            $wpdb->update(
                $this->table_name,
                array(
                    'login_attempts' => $user->login_attempts + 1,
                    'last_login_attempt' => current_time('mysql'),
                ),
                array('id' => $user->id),
                array('%d', '%s'),
                array('%d')
            );

            wp_send_json_error(array('messages' => array(__('Invalid username/email or password.', 'custom-user-auth'))));
            return;
        }

        // Check if password needs rehashing
        if ($this->needs_rehash($user->password_hash)) {
            $new_hash = $this->hash_password($password);
            $wpdb->update(
                $this->table_name,
                array('password_hash' => $new_hash),
                array('id' => $user->id),
                array('%s'),
                array('%d')
            );
        }

        // Reset login attempts and update last login
        $wpdb->update(
            $this->table_name,
            array(
                'login_attempts' => 0,
                'last_login_attempt' => null,
                'last_login' => current_time('mysql'),
            ),
            array('id' => $user->id),
            array('%d', '%s', '%s'),
            array('%d')
        );

        // Create session
        $this->create_user_session($user, $remember);

        do_action('custom_auth_user_logged_in', $user->id, $user->username);

        wp_send_json_success(array(
            'message' => __('Login successful!', 'custom-user-auth'),
            'redirect' => home_url('/dashboard/'),
        ));
    }

    /**
     * Create a user session
     */
    private function create_user_session($user, $remember = false) {
        $token = bin2hex(random_bytes(32));

        $_SESSION['custom_auth_user_id'] = $user->id;
        $_SESSION['custom_auth_username'] = $user->username;
        $_SESSION['custom_auth_email'] = $user->email;
        $_SESSION['custom_auth_token'] = $token;
        $_SESSION['custom_auth_logged_in'] = true;

        if ($remember) {
            $cookie_token = $this->hash_password($token);
            $expiry = time() + (30 * DAY_IN_SECONDS);

            setcookie('custom_auth_remember', $user->id . '|' . $token, $expiry, COOKIEPATH, COOKIE_DOMAIN, is_ssl(), true);
        }
    }

    /**
     * Handle user logout
     */
    public function handle_logout() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        $this->destroy_user_session();

        wp_send_json_success(array(
            'message' => __('You have been logged out.', 'custom-user-auth'),
            'redirect' => home_url(),
        ));
    }

    /**
     * Destroy user session
     */
    private function destroy_user_session() {
        unset($_SESSION['custom_auth_user_id']);
        unset($_SESSION['custom_auth_username']);
        unset($_SESSION['custom_auth_email']);
        unset($_SESSION['custom_auth_token']);
        unset($_SESSION['custom_auth_logged_in']);

        if (isset($_COOKIE['custom_auth_remember'])) {
            setcookie('custom_auth_remember', '', time() - 3600, COOKIEPATH, COOKIE_DOMAIN, is_ssl(), true);
        }

        if (session_id()) {
            session_destroy();
        }
    }

    /**
     * Handle password change
     */
    public function handle_change_password() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        if (!$this->is_user_logged_in()) {
            wp_send_json_error(array('messages' => array(__('You must be logged in to change your password.', 'custom-user-auth'))));
            return;
        }

        global $wpdb;

        $current_password = isset($_POST['current_password']) ? $_POST['current_password'] : '';
        $new_password = isset($_POST['new_password']) ? $_POST['new_password'] : '';
        $confirm_password = isset($_POST['confirm_new_password']) ? $_POST['confirm_new_password'] : '';

        $errors = array();

        if (empty($current_password)) {
            $errors[] = __('Current password is required.', 'custom-user-auth');
        }

        if (empty($new_password)) {
            $errors[] = __('New password is required.', 'custom-user-auth');
        } else {
            $password_errors = $this->validate_password_strength($new_password);
            $errors = array_merge($errors, $password_errors);
        }

        if ($new_password !== $confirm_password) {
            $errors[] = __('New passwords do not match.', 'custom-user-auth');
        }

        if (!empty($errors)) {
            wp_send_json_error(array('messages' => $errors));
            return;
        }

        $user_id = $_SESSION['custom_auth_user_id'];
        $user = $wpdb->get_row(
            $wpdb->prepare("SELECT * FROM {$this->table_name} WHERE id = %d", $user_id)
        );

        if (!$user) {
            wp_send_json_error(array('messages' => array(__('User not found.', 'custom-user-auth'))));
            return;
        }

        // Verify current password
        if (!$this->verify_password($current_password, $user->password_hash)) {
            wp_send_json_error(array('messages' => array(__('Current password is incorrect.', 'custom-user-auth'))));
            return;
        }

        // Hash and store new password
        $new_hash = $this->hash_password($new_password);

        $result = $wpdb->update(
            $this->table_name,
            array(
                'password_hash' => $new_hash,
                'updated_at' => current_time('mysql'),
            ),
            array('id' => $user_id),
            array('%s', '%s'),
            array('%d')
        );

        if ($result === false) {
            wp_send_json_error(array('messages' => array(__('Failed to update password. Please try again.', 'custom-user-auth'))));
            return;
        }

        do_action('custom_auth_password_changed', $user_id);

        wp_send_json_success(array(
            'message' => __('Password changed successfully.', 'custom-user-auth'),
        ));
    }

    /**
     * Check if user is logged in
     */
    public function is_user_logged_in() {
        return isset($_SESSION['custom_auth_logged_in']) && $_SESSION['custom_auth_logged_in'] === true;
    }

    /**
     * Get current logged in user
     */
    public function get_current_user() {
        if (!$this->is_user_logged_in()) {
            return null;
        }

        global $wpdb;
        return $wpdb->get_row(
            $wpdb->prepare("SELECT * FROM {$this->table_name} WHERE id = %d", $_SESSION['custom_auth_user_id'])
        );
    }

