    /**
     * Handle password reset request
     */
    public function handle_password_reset_request() {
        check_ajax_referer('custom_auth_nonce', 'nonce');

        global $wpdb;

        $email = sanitize_email(isset($_POST['email']) ? $_POST['email'] : '');

        if (empty($email) || !is_email($email)) {
            wp_send_json_error(array('messages' => array(__('Please enter a valid email address.', 'custom-user-auth'))));
            return;
        }

        $user = $wpdb->get_row(
            $wpdb->prepare("SELECT * FROM {$this->table_name} WHERE email = %s", $email)
        );

        // Always show success to prevent email enumeration
        if (!$user) {
            wp_send_json_success(array(
                'message' => __('If an account with that email exists, a password reset link has been sent.', 'custom-user-auth'),
            ));
            return;
        }

        // Generate reset token
        $token = bin2hex(random_bytes(32));
        $hashed_token = $this->hash_password($token);
        $expires = date('Y-m-d H:i:s', time() + HOUR_IN_SECONDS);

        $wpdb->update(
            $this->table_name,
            array(
                'password_reset_token' => $hashed_token,
                'password_reset_expires' => $expires,
            ),
            array('id' => $user->id),
            array('%s', '%s'),
            array('%d')
        );

        // Send reset email
        $reset_url = add_query_arg(array(
            'action' => 'reset_password',
            'uid' => $user->id,
            'token' => $token,
        ), home_url('/password-reset/'));

        $subject = __('Password Reset Request', 'custom-user-auth');
        $message = sprintf(
            __("Hello %s,\n\nYou have requested to reset your password. Click the link below to reset it:\n\n%s\n\nThis link will expire in 1 hour.\n\nIf you did not request this, please ignore this email.", 'custom-user-auth'),
            $user->username,
            $reset_url
        );

        wp_mail($email, $subject, $message);

        wp_send_json_success(array(
            'message' => __('If an account with that email exists, a password reset link has been sent.', 'custom-user-auth'),
        ));
    }

