    /**
     * Admin users page
     */
    public function admin_users_page() {
        global $wpdb;

        // Handle user status toggle
        if (isset($_GET['action']) && isset($_GET['user_id']) && isset($_GET['_wpnonce'])) {
            if (wp_verify_nonce($_GET['_wpnonce'], 'custom_auth_toggle_user')) {
                $user_id = intval($_GET['user_id']);
                $action = sanitize_text_field($_GET['action']);

                if ($action === 'deactivate') {
                    $wpdb->update($this->table_name, array('status' => 'inactive'), array('id' => $user_id), array('%s'), array('%d'));
                } elseif ($action === 'activate') {
                    $wpdb->update($this->table_name, array('status' => 'active'), array('id' => $user_id), array('%s'), array('%d'));
                } elseif ($action === 'delete') {
                    $wpdb->delete($this->table_name, array('id' => $user_id), array('%d'));
                } elseif ($action === 'unlock') {
                    $wpdb->update($this->table_name, array('login_attempts' => 0, 'last_login_attempt' => null), array('id' => $user_id), array('%d', '%s'), array('%d'));
                }

                wp_redirect(admin_url('admin.php?page=custom-auth-users&updated=1'));
                exit;
            }
        }

        $users = $wpdb->get_results("SELECT * FROM {$this->table_name} ORDER BY created_at DESC");

        ?>
        <div class="wrap">
            <h1><?php _e('Custom Auth Users', 'custom-user-auth'); ?></h1>

            <?php if (isset($_GET['updated'])) : ?>
                <div class="notice notice-success is-dismissible">
                    <p><?php _e('User updated successfully.', 'custom-user-auth'); ?></p>
                </div>
            <?php endif; ?>

            <table class="widefat striped">
                <thead>
                    <tr>
                        <th><?php _e('ID', 'custom-user-auth'); ?></th>
                        <th><?php _e('Username', 'custom-user-auth'); ?></th>
                        <th><?php _e('Email', 'custom-user-auth'); ?></th>
                        <th><?php _e('Name', 'custom-user-auth'); ?></th>
                        <th><?php _e('Status', 'custom-user-auth'); ?></th>
                        <th><?php _e('Login Attempts', 'custom-user-auth'); ?></th>
                        <th><?php _e('Last Login', 'custom-user-auth'); ?></th>
                        <th><?php _e('Registered', 'custom-user-auth'); ?></th>
                        <th><?php _e('Actions', 'custom-user-auth'); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php if (empty($users)) : ?>
                        <tr>
                            <td colspan="9"><?php _e('No users found.', 'custom-user-auth'); ?></td>
                        </tr>
                    <?php else : ?>
                        <?php foreach ($users as $user) : ?>
                            <tr>
                                <td><?php echo esc_html($user->id); ?></td>
                                <td><?php echo esc_html($user->username); ?></td>
                                <td><?php echo esc_html($user->email); ?></td>
