                                    <?php endif; ?>
                                </td>
                                <td><?php echo $user->last_login ? esc_html(date_i18n(get_option('date_format') . ' ' . get_option('time_format'), strtotime($user->last_login))) : __('Never', 'custom-user-auth'); ?></td>
                                <td><?php echo esc_html(date_i18n(get_option('date_format'), strtotime($user->created_at))); ?></td>
