                                    <?php else : ?>
                                        <a href="<?php echo wp_nonce_url(admin_url('admin.php?page=custom-auth-users&action=activate&user_id=' . $user->id), 'custom_auth_toggle_user'); ?>" class="button button-small"><?php _e('Activate', 'custom-user-auth'); ?></a>
