    $js_content = '
(function($) {
    "use strict";

    // Display messages
    function showMessages(container, messages, type) {
        var $container = $(container);
        $container.empty();

        if (typeof messages === "string") {
            messages = [messages];
        }

        messages.forEach(function(msg) {
            $container.append(\'<div class="message-\' + type + \'">\' + msg + \'</div>\');
        });
    }

    // Password strength checker
    function checkPasswordStrength(password) {
        var strength = 0;

        if (password.length >= 8) strength++;
        if (password.length >= 12) strength++;
        if (/[a-z]/.test(password)) strength++;
        if (/[A-Z]/.test(password)) strength++;
        if (/[0-9]/.test(password)) strength++;
        if (/[^a-zA-Z0-9]/.test(password)) strength++;

        if (strength <= 2) return { level: "weak", text: "Weak password" };
        if (strength <= 4) return { level: "medium", text: "Medium password" };
        return { level: "strong", text: "Strong password" };
    }

    // Password strength indicator
    $(document).on("input", "#reg-password, #new-password", function() {
        var password = $(this).val();
        var $indicator = $(this).siblings(".password-strength");

        if (password.length === 0) {
            $indicator.removeClass("weak medium strong").text("");
            return;
        }

        var result = checkPasswordStrength(password);
        $indicator
            .removeClass("weak medium strong")
            .addClass(result.level)
            .text(result.text);
    });

    // Registration form
    $(document).on("submit", "#custom-auth-register-form", function(e) {
        e.preventDefault();

        var $form = $(this);
        var $btn = $form.find("button[type=submit]");
        var originalText = $btn.text();

        $btn.prop("disabled", true).html(originalText + \' <span class="loading-spinner"></span>\');

        $.ajax({
            url: customAuth.ajaxUrl,
            type: "POST",
            data: {
                action: "custom_auth_register",
                nonce: customAuth.nonce,
                username: $form.find("[name=username]").val(),
                email: $form.find("[name=email]").val(),
                password: $form.find("[name=password]").val(),
                confirm_password: $form.find("[name=confirm_password]").val(),
                first_name: $form.find("[name=first_name]").val(),
                last_name: $form.find("[name=last_name]").val()
            },
            success: function(response) {
                if (response.success) {
                    showMessages("#register-messages", response.data.message, "success");
                    $form[0].reset();
                    $form.find(".password-strength").removeClass("weak medium strong").text("");
                } else {
                    showMessages("#register-messages", response.data.messages, "error");
                }
            },
            error: function() {
                showMessages("#register-messages", "An error occurred. Please try again.", "error");
            },
            complete: function() {
                $btn.prop("disabled", false).text(originalText);
            }
        });
    });

    // Login form
    $(document).on("submit", "#custom-auth-login-form", function(e) {
        e.preventDefault();

        var $form = $(this);
        var $btn = $form.find("button[type=submit]");
        var originalText = $btn.text();

        $btn.prop("disabled", true).html(originalText + \' <span class="loading-spinner"></span>\');

        $.ajax({
            url: customAuth.ajaxUrl,
            type: "POST",
            data: {
                action: "custom_auth_login",
                nonce: customAuth.nonce,
                username: $form.find("[name=username]").val(),
                password: $form.find("[name=password]").val(),
                remember: $form.find("[name=remember]").is(":checked") ? 1 : 0
            },
            success: function(response) {
                if (response.success) {
                    showMessages("#login-messages", response.data.message, "success");
                    if (response.data.redirect) {
                        setTimeout(function() {
                            window.location.href = response.data.redirect;
                        }, 1000);
                    }
                } else {
                    showMessages("#login-messages", response.data.messages, "error");
                }
            },
            error: function() {
                showMessages("#login-messages", "An error occurred. Please try again.", "error");
            },
            complete: function() {
                $btn.prop("disabled", false).text(originalText);
            }
        });
    });

    // Change password form
    $(document).on("submit", "#custom-auth-change-password-form", function(e) {
        e.preventDefault();

        var $form = $(this);
        var $btn = $form.find("button[type=submit]");
        var originalText = $btn.text();

        $btn.prop("disabled", true).html(originalText + \' <span class="loading-spinner"></span>\');

        $.ajax({
            url: customAuth.ajaxUrl,
            type: "POST",
            data: {
                action: "custom_auth_change_password",
                nonce: customAuth.nonce,
                current_password: $form.find("[name=current_password]").val(),
                new_password: $form.find("[name=new_password]").val(),
                confirm_new_password: $form.find("[name=confirm_new_password]").val()
            },
            success: function(response) {
                if (response.success) {
                    showMessages("#change-password-messages", response.data.message, "success");
                    $form[0].reset();
                    $form.find(".password-strength").removeClass("weak medium strong").text("");
                } else {
                    showMessages("#change-password-messages", response.data.messages, "error");
                }
            },
            error: function() {
                showMessages("#change-password-messages", "An error occurred. Please try again.", "error");
            },
            complete: function() {
                $btn.prop("disabled", false).text(originalText);
            }
        });
    });

    // Logout
    $(document).on("click", "#custom-auth-logout-btn, #custom-auth-logout-link", function(e) {
        e.preventDefault();

        $.ajax({
            url: customAuth.ajaxUrl,
            type: "POST",
            data: {
                action: "custom_auth_logout",
                nonce: customAuth.nonce
            },
            success: function(response) {
                if (response.success && response.data.redirect) {
                    window.location.href = response.data.redirect;
                } else {
                    window.location.reload();
                }
            },
            error: function() {
                window.location.reload();
            }
        });
    });

})(jQuery);
';

    file_put_contents($js_dir . 'custom-auth.js', $js_content);
});